using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class ChargeAsyncTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_WithValidCardAndAmount_ReturnsSuccessfulCharge()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_WithMinimumAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_WithLargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_WithZeroAmount_Fails()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_WithNegativeAmount_Fails()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -10.00m);

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task ChargeAsync_WithNullCardToken_ThrowsArgumentNullException()
    {
        await _gateway.ChargeAsync(null!, 50.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_WithEmptyCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(string.Empty, 50.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_WithWhitespaceCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("   ", 50.00m);
    }

    [TestMethod]
    public async Task ChargeAsync_WithDeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    [DataRow(1.00)]
    [DataRow(25.50)]
    [DataRow(100.00)]
    [DataRow(500.99)]
    public async Task ChargeAsync_WithVariousValidAmounts_Succeeds(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class RefundAsyncTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task RefundAsync_WithValidChargeId_ReturnsSuccessfulRefund()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.RefundId));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task RefundAsync_WithNullChargeId_ThrowsArgumentNullException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_WithEmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(string.Empty);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_WithWhitespaceChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync("   ");
    }

    [TestMethod]
    public async Task RefundAsync_WithNonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent_999");

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_ReturnsUniqueRefundIds()
    {
        var result1 = await _gateway.RefundAsync("ch_valid_123");
        var result2 = await _gateway.RefundAsync("ch_valid_456");

        Assert.AreNotEqual(result1.RefundId, result2.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ForAlreadyRefundedCharge_ReturnsFailure()
    {
        await _gateway.RefundAsync("ch_already_refunded");
        var result = await _gateway.RefundAsync("ch_already_refunded");

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }
}

[TestClass]
public class ChargeAndRefundIntegrationTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAndRefund_FullLifecycle_Succeeds()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75.00m);
        Assert.IsTrue(charge.Success);

        var refund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    public async Task ChargeAndRefund_RefundAfterAlreadyRefunded_Fails()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        Assert.IsTrue(charge.Success);

        var firstRefund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(firstRefund.Success);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsFalse(secondRefund.Success);
    }
}

